window.__QUIZ_DATA__=[{"id":"theory>Biology Practical>2004>1>a>i","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"You are provided with specimen A, B,C and D in group I    Group specimens A,B.C and D on the basis of their habitats","images":[],"marking_scheme":"Group specimen A, B, C, and D on the basis of thier habitats. Note that A is an algae (spirogyra), B is a Bony fish, C is a Tadpole, D is a Lizard Specimen A, B, C can be found in fresh water habitats or ponds or streams Specimen D can be found in terrestrial habitat or on land","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>1>a>ii","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Tabulate five differences between specimens B and D","images":[],"marking_scheme":"Specimen B (Bony Fish)Specimen D (Lizard)Absence of neckPresence of neckAbsence of gular foldPresence of gular foldAbsence of eye lidPresence of eye lidPresence of operculumAbsence of operculumPresence of gillsAbsence of gillsPresence of lateral linesAbsence of lateral linesAbsence of legsPresence of legsAbsence of eardrumPresence of eardrumPresence of short muscular tailPresence of long tailDetachable scales covers the bodyBody covered with non detachable scalesAbsence of nuchal crestPresence of nuchal crest","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>1>b>i","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Make a 10 cm to 12 cm long diagram of the dorsal view of specimen D from head to mid-trunk and label it","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>1>b>ii","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"State the sex of specimen D giving two reasons","images":[],"marking_scheme":"The sex of specimen D is female The reasons are   (a) it is greenish brown and dull in colour  (b) it has no nuchal crest   (c) It has no gular fold   (d) If however it a male then the reasons are It is orange in colour and bright, it has nuchal crest, It has gular fold, it has hemipenis, It has anal pad around cloaca","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>1>c>i","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"i","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Construct a food chain involving specimens A,B,C and D","images":[],"marking_scheme":"Constructing food chain involving specimens A, B, C, D. A (alga) \u2192 C (tadpole) \u2192  B (bony fish)","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>1>c>ii","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"ii","group":"","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Explain the effect of introducing more of specimen C in it's habitat","images":[],"marking_scheme":"The effects of introducing more of specimen C (tadpole) to the habitat. The algal population will decrease which will result in competition among tadpoles, leading to the death of some tadpoles. Moreover introducing more tadpole will provide more food for the fish.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>2>a","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"a","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Specimen K, in group II is a thin transverse/cross section of a portion of the plant Talinum species stained with Aniline sulphate/Acidified phloroglucinol and mounted in a drop of dilute glycerine. Similarly, specimen K, in group III is a thin transverse/cross section of a portion of the plant Talinum species stained with a reagent and mounted in a drop of dilute glycerine    Examine specimens K, and K\u2082 under the low power of a light microscope or hand lens (x 10) and identify the portion/ organ of the Talinum species from which the thin sections were cut, without giving reasons","images":[],"marking_scheme":"The organ K, is the stem of a dicotyledonous (water leaf) stem","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2004>2>b","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"b","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Make a labelled drawing of 7 cm to 8 cm in diameter of tissue distribution of specimen K, which had been treated with a reagent to stain lignified walls","images":["data:image/jpeg;base64,"],"marking_scheme":"Outline of tissue in specimen K/Tissue distribution in specimen K/Cross section/Transverse section of specimen K.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>2>c","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"c","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Specimen K, has been stained with a reagent to show the contents of the cells. State the name of the reagent used, giving your reasons","images":[],"marking_scheme":"The name of the reagent used is lodine solution because starch grains in the cells showed blue- black colouration","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>2>d","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"d","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"State the names of the two major areas in the transverse/ cross sections which contain parenchyma cells","images":[],"marking_scheme":"The area with parenchyma cells are. The cortex the pith and medullary rays","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>2>e","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"e","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"State four observable features of specimens K, and K, which suggest four functions performed by the parenchyma cells of the portion/organ from which the specimens were cut","images":[],"marking_scheme":"-The cells look turgid which provide mechanical strength  -The cells contain chloroplasts and carry out photosynthesis   -The cells contains starch grains therefore are food storage centres  -The cells are compactly arranged therefore give support of mechnical strength  -There are intercellular spaces for gaseous exchange","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>3>a>i","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"i","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Specimen J in group III is a component structure obtained from a small mammalian skeleton Examine specimen J carefully and answer the following questions    What part of the mammalian body was specimen J obtained from?","images":[],"marking_scheme":"Specimen J is the part of skull of a mammalian herbivore","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>3>a>ii","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"ii","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"What name is given to specimen J?","images":[],"marking_scheme":"Specimen J is the lower jaw of a herbivore","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2004>3>a>iii","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"iii","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Mention the phylum to which specimen J belongs","images":[],"marking_scheme":"Specimen J belong to phylum chordata or vertebrata","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2004>3>b>i","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"i","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Make a labelled drawing of 8 cm to 10 cm long of the lateral view of specimen J","images":["data:image/jpeg;base64,"],"marking_scheme":"Drawing of specimen J","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>3>b>ii","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"ii","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Suggest the feeding habit of the animal","images":[],"marking_scheme":"The feeding habit of specimen J is herbivorous mode of feeding or feeds on plants","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>3>b>iii","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"iii","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"What is of biological interest about specimen J?","images":[],"marking_scheme":"The biological interest is the wide space or gap (diastema) between the incisors and the first premolar.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2004>3>b>iv","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"iv","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Name the missing structure in specimen J","images":[],"marking_scheme":"The missing structure of specimen J are the canines","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2004>3>c>i","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"i","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Describe the different observable structures/components in dentition of specimen J and their adaptations to the feeding habit of the animal","images":[],"marking_scheme":"The description of the different dental structures and their adaptation to the feeding habit of the animal.  (a) The incisor is long and curved. It is chisel shaped for cutting and gnawing  (b) The diastema is a wide gap between the insisor and first premolar and allows the tongue to move the food round the mouth for effective grinding  (c) The premolars are broad and ridged. They have cusps and are used for grinding and chewing  (d) The molars are broad and ridged They have cusps and are used for grinding","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2004>3>c>ii","subject":"Biology Practical","year":"2004","type":"Practical","sub_label":"ii","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Give two examples of animals with the type of dentition seen with specimen J","images":[],"marking_scheme":"The examples of animals with the type of dentition seen in specimen J are: Rabbit, Cow, Goat, Sheep, Squirrel, Horse, Guinea pig, Donkey, Rat and Hare.","marks":"1","difficulty":"2"}];